import{f as a,o as e,c as r,a2 as s}from"./chunks/framework.Ccw_j35p.js";const b=JSON.parse('{"title":"中间件","description":"","frontmatter":{},"headers":[],"relativePath":"middleware/index.md","filePath":"middleware/index.md","lastUpdated":1780747276000}'),o={name:"middleware/index.md"};function i(l,t,d,n,h,c){return e(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="中间件" tabindex="-1">中间件 <a class="header-anchor" href="#中间件" aria-label="Permalink to &quot;中间件&quot;">​</a></h1><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>中间件是分布式系统的骨架，负责消息传递、服务治理、数据同步等关键职责。掌握主流中间件的使用和原理，是区分初级与高级工程师的重要分水岭。本模块已全面覆盖 <strong>Kafka / RocketMQ / ZooKeeper / Nacos / Dubbo</strong> 五大核心中间件，包含完整的三级知识图谱（入门→进阶→经典高频）、核心原理深度解析和经典高频面试题。</p><div class="tip custom-block"><p class="custom-block-title">核心思路</p><p>消息队列的重点是<strong>可靠性保证</strong>（不丢消息）和<strong>高性能设计</strong>（零拷贝/顺序写）；注册中心的重点是<strong>CAP 取舍</strong>和<strong>健康检查</strong>；RPC 框架的重点是<strong>服务调用全链路</strong>和<strong>SPI 扩展机制</strong>。</p></div><div class="info custom-block"><p class="custom-block-title">内容特色</p><ul><li>每个中间件包含 <strong>6 个核心原理深度解析要点</strong></li><li>每个中间件附带 <strong>6 道经典高频面试题</strong>（含完整深入答案）</li><li>分布式理论基础章节覆盖 CAP / BASE / Paxos / Raft / ZAB 等核心理论</li><li>基于 2025-2026 年最新版本（Kafka 4.0 KRaft / RocketMQ 5.5.0 / ZooKeeper 3.9.4 / Nacos 3.2.x / Dubbo 3.x）</li></ul></div><h2 id="知识域导航" tabindex="-1">知识域导航 <a class="header-anchor" href="#知识域导航" aria-label="Permalink to &quot;知识域导航&quot;">​</a></h2><h3 id="分布式理论基础" tabindex="-1">分布式理论基础 <a class="header-anchor" href="#分布式理论基础" aria-label="Permalink to &quot;分布式理论基础&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./distributed-system/">分布式理论</a></td><td>分布式系统定义、核心挑战、知识域总览</td></tr><tr><td><a href="./distributed-system/cap-base">CAP 与 BASE</a></td><td>CAP 定理深度解析、BASE 理论、分布式一致性模型</td></tr><tr><td><a href="./distributed-system/consensus">一致性协议</a></td><td>Paxos / Raft / ZAB / 2PC-3PC / Gossip 协议</td></tr><tr><td><a href="./distributed-system/transaction">分布式事务</a></td><td>2PC / 3PC / TCC / Saga / Seata 方案对比</td></tr><tr><td><a href="./distributed-system/id-generator">分布式 ID</a></td><td>UUID / 雪花算法 / 数据库号段 / Redis 方案</td></tr></tbody></table><h3 id="消息队列" tabindex="-1">消息队列 <a class="header-anchor" href="#消息队列" aria-label="Permalink to &quot;消息队列&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./message-queue/">MQ 概览</a></td><td>消息队列核心概念、Kafka vs RocketMQ vs RabbitMQ 选型对比</td></tr><tr><td><a href="./message-queue/kafka">Kafka 核心</a></td><td>分区机制、ISR、水位线、幂等性、Exactly-Once、KRaft 共识</td></tr><tr><td><a href="./message-queue/rocketmq">RocketMQ 核心</a></td><td>事务消息、顺序消息、CommitLog 存储、DLedger 高可用</td></tr><tr><td><a href="./message-queue/reliability">消息可靠性</a></td><td>消息不丢失三端保证、幂等消费、消息堆积处理、事务消息对比</td></tr></tbody></table><h3 id="分布式协调与服务治理" tabindex="-1">分布式协调与服务治理 <a class="header-anchor" href="#分布式协调与服务治理" aria-label="Permalink to &quot;分布式协调与服务治理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./distributed-system/zookeeper">ZooKeeper 核心</a></td><td>ZAB 协议、分布式锁、Watcher 机制、Session 管理</td></tr><tr><td><a href="./distributed-system/nacos">Nacos 核心</a></td><td>Distro 协议、AP/CP 双模、配置动态刷新、健康检查</td></tr><tr><td><a href="./distributed-system/dubbo">Dubbo 核心</a></td><td>SPI 机制、Triple 协议、服务调用全链路、线程模型</td></tr></tbody></table><h2 id="面试重点" tabindex="-1">面试重点 <a class="header-anchor" href="#面试重点" aria-label="Permalink to &quot;面试重点&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">高频考点</p><ol><li><strong>消息不丢失</strong>：Kafka / RocketMQ 在 Producer / Broker / Consumer 三个环节如何保证可靠性？</li><li><strong>消息重复消费</strong>：什么情况下会重复？如何做幂等？（数据库唯一键 + Redis + 业务状态机）</li><li><strong>消息积压</strong>：积压原因分析、紧急处理方案（临时扩容 Consumer）、长期治理策略</li><li><strong>RocketMQ 事务消息</strong>：半消息 → 执行本地事务 → 发送确认/回查的完整流程</li><li><strong>Kafka ISR 机制</strong>：为什么设计 ISR 而不是简单的同步/异步复制？</li><li><strong>Kafka Exactly-Once</strong>：幂等生产者 + 事务 API 的双维度实现原理</li><li><strong>Nacos AP vs CP</strong>：Distro 协议 vs Raft 协议，临时实例 vs 持久实例的选型</li><li><strong>ZooKeeper 分布式锁</strong>：临时顺序节点 + Watch 前驱 vs Redis Redlock 对比</li><li><strong>Dubbo 调用全链路</strong>：从 Consumer 到 Provider 的 16 步完整路径</li><li><strong>Raft 安全性</strong>：选举限制、提交限制、日志匹配性质三点保证</li><li><strong>CAP 定理</strong>：为什么不能同时满足三者？CP vs AP 的工程取舍</li><li><strong>脑裂</strong>：为什么集群推荐奇数节点？Quorum 机制如何避免脑裂？</li></ol></div><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>只会用不会排查问题：消息丢了不知道从哪个环节查</li><li>把 Kafka 和 RocketMQ 的适用场景搞混，说不出选型依据</li><li>分布式事务一上来就说 Seata，不考虑业务场景是否适合</li><li>对 Nacos 中 CP/AP 的理解停留在概念，说不出具体协议（Distro / Raft）</li><li>ZooKeeper 的分布式锁只会说&quot;临时节点&quot;，不知道羊群效应和顺序节点方案</li><li>Dubbo 只知道用注解，不知道 Filter 链和 SPI 扩展机制</li></ul></div><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><h3 id="阶段一-分布式理论奠基-1-周" tabindex="-1">阶段一：分布式理论奠基（1 周） <a class="header-anchor" href="#阶段一-分布式理论奠基-1-周" aria-label="Permalink to &quot;阶段一：分布式理论奠基（1 周）&quot;">​</a></h3><ol><li>通读 <a href="./distributed-system/">分布式理论</a> → <a href="./distributed-system/cap-base">CAP 与 BASE</a> → <a href="./distributed-system/consensus">一致性协议</a></li><li>理解 CAP 定理的本质选择和 BASE 理论的设计哲学</li><li>掌握 Raft 协议的三大子问题和安全性保证</li></ol><h3 id="阶段二-分布式协调-1-周" tabindex="-1">阶段二：分布式协调（1 周） <a class="header-anchor" href="#阶段二-分布式协调-1-周" aria-label="Permalink to &quot;阶段二：分布式协调（1 周）&quot;">​</a></h3><ol start="4"><li>学习 <a href="./distributed-system/zookeeper">ZooKeeper 核心</a>，理解 ZAB 协议和分布式锁实现</li><li>学习 <a href="./distributed-system/nacos">Nacos 核心</a>，对比 AP/CP 双模式的实际应用</li></ol><h3 id="阶段三-消息队列核心-2-周" tabindex="-1">阶段三：消息队列核心（2 周） <a class="header-anchor" href="#阶段三-消息队列核心-2-周" aria-label="Permalink to &quot;阶段三：消息队列核心（2 周）&quot;">​</a></h3><ol start="6"><li>学习 <a href="./message-queue/kafka">Kafka 核心</a>，搭建集群环境，对比吞吐和延迟</li><li>学习 <a href="./message-queue/rocketmq">RocketMQ 核心</a>，跑通全部消息类型</li><li>阅读 <a href="./message-queue/reliability">消息可靠性</a>，模拟消息丢失/重复/积压场景</li></ol><h3 id="阶段四-rpc-框架-1-周" tabindex="-1">阶段四：RPC 框架（1 周） <a class="header-anchor" href="#阶段四-rpc-框架-1-周" aria-label="Permalink to &quot;阶段四：RPC 框架（1 周）&quot;">​</a></h3><ol start="9"><li>学习 <a href="./distributed-system/dubbo">Dubbo 核心</a>，理解 SPI 机制和 Triple 协议</li><li>搭建 Dubbo + Nacos 的微服务 Demo，追踪完整调用链路</li></ol><details class="details custom-block"><summary>推荐书单</summary><ul><li>《RocketMQ 实战与原理解析》—— 杨开元</li><li>《Apache Kafka 实战》—— 胡夕</li><li>《深入理解 Kafka：核心设计与实践原理》—— 朱忠华</li><li>《从 Paxos 到 ZooKeeper：分布式一致性原理与实践》—— 倪超</li><li>《Nacos 架构与原理》—— Nacos 官方文档</li><li>《Apache Dubbo 官方文档》</li><li>《In Search of an Understandable Consensus Algorithm》（Raft 论文）</li></ul></details>',25)])])}const m=a(o,[["render",i]]);export{b as __pageData,m as default};
